1	package com.nutriops.app.data.repository
2	
3	import com.nutriops.app.config.AppConfig
4	import com.nutriops.app.data.local.NutriOpsDatabase
5	import com.nutriops.app.domain.model.ReminderStatus
6	import com.nutriops.app.logging.AppLogger
7	import kotlinx.coroutines.Dispatchers
8	import kotlinx.coroutines.withContext
9	import java.time.LocalDate
10	import java.time.LocalDateTime
11	import java.time.LocalTime
12	import java.time.format.DateTimeFormatter
13	import java.util.UUID
14	import javax.inject.Inject
15	import javax.inject.Singleton
16	
17	@Singleton
18	class MessageRepository @Inject constructor(
19	    private val database: NutriOpsDatabase
20	) {
21	    private val msgQueries get() = database.messagesQueries
22	
23	    // ── Templates ──
24	
25	    suspend fun createTemplate(
26	        name: String, titleTemplate: String, bodyTemplate: String,
27	        variablesJson: String, triggerEvent: String
28	    ): Result<String> = withContext(Dispatchers.IO) {
29	        try {
30	            val id = UUID.randomUUID().toString()
31	            val now = LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
32	            msgQueries.insertMessageTemplate(id, name, titleTemplate, bodyTemplate, variablesJson, triggerEvent, 1, now, now)
33	            Result.success(id)
34	        } catch (e: Exception) {
35	            Result.failure(e)
36	        }
37	    }
38	
39	    suspend fun getTemplateByTrigger(triggerEvent: String) = withContext(Dispatchers.IO) {
40	        msgQueries.getTemplateByTrigger(triggerEvent).executeAsList()
41	    }
42	
43	    suspend fun getAllTemplates() = withContext(Dispatchers.IO) {
44	        msgQueries.getAllTemplates().executeAsList()
45	    }
46	
47	    // ── Messages ──
48	
49	    suspend fun sendMessage(
50	        userId: String, templateId: String?, title: String, body: String,
51	        messageType: String, triggerEvent: String
52	    ): Result<String> = withContext(Dispatchers.IO) {
53	        try {
54	            val id = UUID.randomUUID().toString()
55	            val now = LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
56	            msgQueries.insertMessage(id, userId, templateId, title, body, messageType, triggerEvent, 0, now)
57	            AppLogger.info("MessageRepo", "Message sent to user=$userId type=$messageType trigger=$triggerEvent")
58	            Result.success(id)
59	        } catch (e: Exception) {
60	            Result.failure(e)
61	        }
62	    }
63	
64	    suspend fun getMessagesByUserId(userId: String) = withContext(Dispatchers.IO) {
65	        msgQueries.getMessagesByUserId(userId).executeAsList()
66	    }
67	
68	    suspend fun getUnreadMessages(userId: String) = withContext(Dispatchers.IO) {
69	        msgQueries.getUnreadMessagesByUserId(userId).executeAsList()
70	    }
71	
72	    suspend fun getUnreadCount(userId: String) = withContext(Dispatchers.IO) {
73	        msgQueries.getUnreadMessageCount(userId).executeAsOne()
74	    }
75	
76	    suspend fun markAsRead(messageId: String) = withContext(Dispatchers.IO) {
77	        msgQueries.markMessageAsRead(messageId)
78	    }
79	
80	    suspend fun markAllAsRead(userId: String) = withContext(Dispatchers.IO) {
81	        msgQueries.markAllMessagesAsRead(userId)
82	    }
83	
84	    // ── Reminders (quiet hours + daily cap) ──
85	
86	    suspend fun scheduleReminder(
87	        userId: String, messageId: String?, title: String, scheduledAt: String
88	    ): Result<String> = withContext(Dispatchers.IO) {
89	        try {
90	            val id = UUID.randomUUID().toString()
91	            val now = LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
92	            msgQueries.insertReminder(id, userId, messageId, title, scheduledAt, null, ReminderStatus.PENDING.name, now)
93	            Result.success(id)
94	        } catch (e: Exception) {
95	            Result.failure(e)
96	        }
97	    }
98	
99	    suspend fun deliverReminder(reminderId: String): Result<ReminderStatus> = withContext(Dispatchers.IO) {
100	        try {
101	            val reminder = msgQueries.getReminderById(reminderId).executeAsOneOrNull()
102	                ?: return@withContext Result.failure(IllegalArgumentException("Reminder not found"))
103	
104	            val now = LocalDateTime.now()
105	            val nowStr = now.format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
106	
107	            // Check quiet hours (9:00 PM - 7:00 AM)
108	            if (isQuietHours(now)) {
109	                msgQueries.updateReminderStatus(ReminderStatus.SKIPPED_QUIET_HOURS.name, null, reminderId)
110	                AppLogger.info("MessageRepo", "Reminder $reminderId skipped: quiet hours")
111	                return@withContext Result.success(ReminderStatus.SKIPPED_QUIET_HOURS)
112	            }
113	
114	            // Check daily cap (max 3 per day)
115	            val todayStart = now.toLocalDate().atStartOfDay().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
116	            val todayEnd = now.toLocalDate().plusDays(1).atStartOfDay().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
117	            val deliveredToday = msgQueries.getDeliveredRemindersToday(reminder.userId, todayStart, todayEnd).executeAsOne()
118	
119	            if (deliveredToday >= AppConfig.MAX_REMINDERS_PER_DAY) {
120	                msgQueries.updateReminderStatus(ReminderStatus.SKIPPED_CAP_REACHED.name, null, reminderId)
121	                AppLogger.info("MessageRepo", "Reminder $reminderId skipped: daily cap reached ($deliveredToday)")
122	                return@withContext Result.success(ReminderStatus.SKIPPED_CAP_REACHED)
123	            }
124	
125	            // Deliver
126	            msgQueries.updateReminderStatus(ReminderStatus.DELIVERED.name, nowStr, reminderId)
127	            AppLogger.info("MessageRepo", "Reminder $reminderId delivered to user=${reminder.userId}")
128	            Result.success(ReminderStatus.DELIVERED)
129	        } catch (e: Exception) {
130	            Result.failure(e)
131	        }
132	    }
133	
134	    suspend fun getPendingReminders(beforeTime: String) = withContext(Dispatchers.IO) {
135	        msgQueries.getPendingReminders(beforeTime).executeAsList()
136	    }
137	
138	    suspend fun getRemindersByUserId(userId: String) = withContext(Dispatchers.IO) {
139	        msgQueries.getRemindersByUserId(userId).executeAsList()
140	    }
141	
142	    // ── Todo Items ──
143	
144	    suspend fun createTodo(
145	        userId: String, title: String, description: String,
146	        dueDate: String?, relatedEntityType: String?, relatedEntityId: String?
147	    ): Result<String> = withContext(Dispatchers.IO) {
148	        try {
149	            val id = UUID.randomUUID().toString()
150	            val now = LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
151	            msgQueries.insertTodoItem(id, userId, title, description, 0, dueDate, relatedEntityType, relatedEntityId, now, now)
152	            Result.success(id)
153	        } catch (e: Exception) {
154	            Result.failure(e)
155	        }
156	    }
157	
158	    suspend fun completeTodo(todoId: String) = withContext(Dispatchers.IO) {
159	        val now = LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
160	        msgQueries.updateTodoCompletion(1, now, todoId)
161	    }
162	
163	    suspend fun getTodosByUserId(userId: String) = withContext(Dispatchers.IO) {
164	        msgQueries.getTodosByUserId(userId).executeAsList()
165	    }
166	
167	    suspend fun getIncompleteTodos(userId: String) = withContext(Dispatchers.IO) {
168	        msgQueries.getIncompleteTodosByUserId(userId).executeAsList()
169	    }
170	
171	    private fun isQuietHours(dateTime: LocalDateTime): Boolean {
172	        val time = dateTime.toLocalTime()
173	        val quietStart = LocalTime.parse(AppConfig.QUIET_HOURS_START)
174	        val quietEnd = LocalTime.parse(AppConfig.QUIET_HOURS_END)
175	
176	        return if (quietStart > quietEnd) {
177	            // Crosses midnight: 21:00 - 07:00
178	            time >= quietStart || time < quietEnd
179	        } else {
180	            time in quietStart..quietEnd
181	        }
182	    }
183	}
