43	    fun load() {
44	        viewModelScope.launch {
45	            val session = authManager.currentSession.value ?: return@launch
46	            val msgs = messagingUseCase.getMessages(session.userId)
47	            _messages.value = msgs.map { MessageUiItem(it.id, it.title, it.body, it.messageType, it.isRead == 1L, it.createdAt) }
48	            val tds = messagingUseCase.getTodos(session.userId)
49	            _todos.value = tds.map { TodoUiItem(it.id, it.title, it.description, it.isCompleted == 1L, it.dueDate) }
50	        }
51	    }
