69	@OptIn(ExperimentalMaterial3Api::class)
70	@Composable
71	fun UserMessagesScreen(
72	    onBack: () -> Unit,
73	    viewModel: UserMessagesViewModel = hiltViewModel()
74	) {
75	    val messages by viewModel.messages.collectAsState()
76	    val todos by viewModel.todos.collectAsState()
77	    var selectedTab by remember { mutableIntStateOf(0) }
78	
79	    Scaffold(
80	        topBar = {
81	            TopAppBar(
82	                title = { Text("Messages & Todos") },
83	                navigationIcon = { IconButton(onClick = onBack) { Icon(Icons.AutoMirrored.Filled.ArrowBack, "Back") } },
84	                actions = {
85	                    if (selectedTab == 0) TextButton(onClick = { viewModel.markAllAsRead() }) { Text("Mark All Read") }
86	                }
87	            )
88	        }
89	    ) { padding ->
90	        Column(modifier = Modifier.fillMaxSize().padding(padding)) {
91	            TabRow(selectedTabIndex = selectedTab) {
92	                Tab(selected = selectedTab == 0, onClick = { selectedTab = 0 }, text = { Text("Messages (${messages.count { !it.isRead }})") })
93	                Tab(selected = selectedTab == 1, onClick = { selectedTab = 1 }, text = { Text("Todos (${todos.count { !it.isCompleted }})") })
94	            }
95	
96	            when (selectedTab) {
97	                0 -> LazyColumn(modifier = Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(6.dp)) {
98	                    items(messages) { msg ->
99	                        Card(
100	                            onClick = { if (!msg.isRead) viewModel.markAsRead(msg.id) },
101	                            modifier = Modifier.fillMaxWidth(),
102	                            colors = if (!msg.isRead) CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.primaryContainer) else CardDefaults.cardColors()
103	                        ) {
104	                            Column(modifier = Modifier.padding(12.dp)) {
105	                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
106	                                    Text(msg.title, style = MaterialTheme.typography.titleSmall, modifier = Modifier.weight(1f))
107	                                    if (!msg.isRead) Icon(Icons.Default.Circle, null, tint = MaterialTheme.colorScheme.primary, modifier = Modifier.size(8.dp))
108	                                }
109	                                Text(msg.body, style = MaterialTheme.typography.bodySmall, maxLines = 2)
110	                                Text("${msg.type} | ${msg.createdAt}", style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
111	                            }
112	                        }
113	                    }
114	                    if (messages.isEmpty()) { item { Text("No messages yet", style = MaterialTheme.typography.bodyMedium) } }
115	                }
116	                1 -> LazyColumn(modifier = Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(6.dp)) {
117	                    items(todos) { todo ->
118	                        Card(modifier = Modifier.fillMaxWidth()) {
119	                            Row(modifier = Modifier.padding(12.dp)) {
120	                                IconButton(onClick = { if (!todo.isCompleted) viewModel.completeTodo(todo.id) }) {
121	                                    Icon(
122	                                        if (todo.isCompleted) Icons.Default.CheckCircle else Icons.Default.Circle,
123	                                        null,
124	                                        tint = if (todo.isCompleted) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant
125	                                    )
126	                                }
127	                                Column(modifier = Modifier.weight(1f)) {
128	                                    Text(todo.title, style = MaterialTheme.typography.titleSmall)
129	                                    if (todo.description.isNotBlank()) Text(todo.description, style = MaterialTheme.typography.bodySmall)
130	                                    todo.dueDate?.let { Text("Due: $it", style = MaterialTheme.typography.labelSmall) }
131	                                }
132	                            }
133	                        }
134	                    }
135	                    if (todos.isEmpty()) { item { Text("No todo items", style = MaterialTheme.typography.bodyMedium) } }
136	                }
137	            }
138	        }
139	    }
140	}
