96	            msgQueries.insertReminder(id, userId, messageId, title, scheduledAt, null, ReminderStatus.PENDING.name, now)
97	            Result.success(id)
98	        } catch (e: Exception) {
99	            Result.failure(e)
100	        }
101	    }
