103	    suspend fun deliverReminder(reminderId: String): Result<ReminderStatus> = withContext(Dispatchers.IO) {
104	        try {
105	            val reminder = msgQueries.getReminderById(reminderId).executeAsOneOrNull()
106	                ?: return@withContext Result.failure(IllegalArgumentException("Reminder not found"))
107	
108	            val now = LocalDateTime.now()
109	            val nowStr = now.format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
110	
111	            // Check quiet hours (9:00 PM - 7:00 AM)
112	            if (isQuietHours(now)) {
113	                msgQueries.updateReminderStatus(ReminderStatus.SKIPPED_QUIET_HOURS.name, null, reminderId)
114	                AppLogger.info("MessageRepo", "Reminder $reminderId skipped: quiet hours")
115	                return@withContext Result.success(ReminderStatus.SKIPPED_QUIET_HOURS)
116	            }
117	
118	            // Check daily cap (max 3 per day)
119	            val todayStart = now.toLocalDate().atStartOfDay().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
120	            val todayEnd = now.toLocalDate().plusDays(1).atStartOfDay().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
121	            val deliveredToday = msgQueries.getDeliveredRemindersToday(reminder.userId, todayStart, todayEnd).executeAsOne()
122	
123	            if (deliveredToday >= AppConfig.MAX_REMINDERS_PER_DAY) {
124	                msgQueries.updateReminderStatus(ReminderStatus.SKIPPED_CAP_REACHED.name, null, reminderId)
125	                AppLogger.info("MessageRepo", "Reminder $reminderId skipped: daily cap reached ($deliveredToday)")
126	                return@withContext Result.success(ReminderStatus.SKIPPED_CAP_REACHED)
127	            }
128	
129	            // Deliver
130	            msgQueries.updateReminderStatus(ReminderStatus.DELIVERED.name, nowStr, reminderId)
131	            AppLogger.info("MessageRepo", "Reminder $reminderId delivered to user=${reminder.userId}")
132	            Result.success(ReminderStatus.DELIVERED)
133	        } catch (e: Exception) {
134	            Result.failure(e)
135	        }
