124	                msgQueries.updateReminderStatus(ReminderStatus.SKIPPED_CAP_REACHED.name, null, reminderId)
125	                AppLogger.info("MessageRepo", "Reminder $reminderId skipped: daily cap reached ($deliveredToday)")
126	                return@withContext Result.success(ReminderStatus.SKIPPED_CAP_REACHED)
127	            }
128	
129	            // Deliver
130	            msgQueries.updateReminderStatus(ReminderStatus.DELIVERED.name, nowStr, reminderId)
131	            AppLogger.info("MessageRepo", "Reminder $reminderId delivered to user=${reminder.userId}")
132	            Result.success(ReminderStatus.DELIVERED)
133	        } catch (e: Exception) {
134	            Result.failure(e)
135	        }
136	    }
137	
138	    suspend fun getPendingReminders(beforeTime: String) = withContext(Dispatchers.IO) {
139	        msgQueries.getPendingReminders(beforeTime).executeAsList()
140	    }
141	
142	    suspend fun getRemindersByUserId(userId: String) = withContext(Dispatchers.IO) {
143	        msgQueries.getRemindersByUserId(userId).executeAsList()
144	    }
145	
146	    // ── Todo Items ──
147	
148	    suspend fun createTodo(
149	        userId: String, title: String, description: String,
150	        dueDate: String?, relatedEntityType: String?, relatedEntityId: String?
151	    ): Result<String> = withContext(Dispatchers.IO) {
152	        try {
153	            val id = UUID.randomUUID().toString()
154	            val now = LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
155	            msgQueries.insertTodoItem(id, userId, title, description, 0, dueDate, relatedEntityType, relatedEntityId, now, now)
156	            Result.success(id)
157	        } catch (e: Exception) {
158	            Result.failure(e)
159	        }
160	    }
161	
162	    suspend fun completeTodo(todoId: String) = withContext(Dispatchers.IO) {
163	        val now = LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
164	        msgQueries.updateTodoCompletion(1, now, todoId)
165	    }
166	
167	    suspend fun getTodosByUserId(userId: String) = withContext(Dispatchers.IO) {
168	        msgQueries.getTodosByUserId(userId).executeAsList()
169	    }
170	
171	    suspend fun getIncompleteTodos(userId: String) = withContext(Dispatchers.IO) {
172	        msgQueries.getIncompleteTodosByUserId(userId).executeAsList()
173	    }
174	
175	    private fun isQuietHours(dateTime: LocalDateTime): Boolean {
176	        val time = dateTime.toLocalTime()
177	        val quietStart = LocalTime.parse(AppConfig.QUIET_HOURS_START)
178	        val quietEnd = LocalTime.parse(AppConfig.QUIET_HOURS_END)
179	
180	        return if (quietStart > quietEnd) {
181	            // Crosses midnight: 21:00 - 07:00
182	            time >= quietStart || time < quietEnd
183	        } else {
184	            time in quietStart..quietEnd
185	        }
186	    }
187	}
