175	    private fun isQuietHours(dateTime: LocalDateTime): Boolean {
176	        val time = dateTime.toLocalTime()
177	        val quietStart = LocalTime.parse(AppConfig.QUIET_HOURS_START)
178	        val quietEnd = LocalTime.parse(AppConfig.QUIET_HOURS_END)
179	
180	        return if (quietStart > quietEnd) {
181	            // Crosses midnight: 21:00 - 07:00
182	            time >= quietStart || time < quietEnd
183	        } else {
184	            time in quietStart..quietEnd
185	        }
186	    }
