3	import android.util.Log
4	import com.nutriops.app.config.AppConfig
5	
6	/**
7	 * Centralized logging with structured format and automatic PII/sensitive data redaction.
8	 * Format: [module][sub-module] message
9	 *
10	 * All application logging MUST go through this logger to ensure:
11	 * 1. Consistent structured format
12	 * 2. Automatic redaction of sensitive data
13	 * 3. Configurable log levels
14	 * 4. No sensitive data leakage in logs
15	 */
16	object AppLogger {
17	
18	    private const val TAG = "NutriOps"
19	
20	    private val SENSITIVE_PATTERNS = listOf(
21	        Regex("password[\":\\s]*[\"']?[^\"',\\s}]+", RegexOption.IGNORE_CASE),
22	        Regex("passwordHash[\":\\s]*[\"']?[^\"',\\s}]+", RegexOption.IGNORE_CASE),
23	        Regex("token[\":\\s]*[\"']?[^\"',\\s}]+", RegexOption.IGNORE_CASE),
24	        Regex("secret[\":\\s]*[\"']?[^\"',\\s}]+", RegexOption.IGNORE_CASE),
25	        Regex("\\b\\d{3}-\\d{2}-\\d{4}\\b"), // SSN
26	        Regex("encryptionKey[\":\\s]*[\"']?[^\"',\\s}]+", RegexOption.IGNORE_CASE),
27	        Regex("compensationAmount[\":\\s]*[\"']?[\\d.]+", RegexOption.IGNORE_CASE),
28	        Regex("creditCard[\":\\s]*[\"']?[\\d-]+", RegexOption.IGNORE_CASE),
29	    )
30	
31	    private val REDACTION_REPLACEMENT = "***REDACTED***"
32	
33	    fun debug(module: String, message: String, subModule: String? = null) {
34	        if (shouldLog(LogLevel.DEBUG)) {
35	            Log.d(TAG, formatMessage(module, subModule, redact(message)))
36	        }
37	    }
38	
39	    fun info(module: String, message: String, subModule: String? = null) {
40	        if (shouldLog(LogLevel.INFO)) {
41	            Log.i(TAG, formatMessage(module, subModule, redact(message)))
42	        }
43	    }
44	
45	    fun warn(module: String, message: String, subModule: String? = null) {
46	        if (shouldLog(LogLevel.WARN)) {
47	            Log.w(TAG, formatMessage(module, subModule, redact(message)))
48	        }
49	    }
50	
51	    fun error(module: String, message: String, throwable: Throwable? = null, subModule: String? = null) {
52	        if (shouldLog(LogLevel.ERROR)) {
53	            val formatted = formatMessage(module, subModule, redact(message))
54	            if (throwable != null) {
55	                Log.e(TAG, formatted, throwable)
56	            } else {
57	                Log.e(TAG, formatted)
58	            }
59	        }
60	    }
61	
62	    fun audit(module: String, action: String, actorId: String, entityType: String, entityId: String) {
63	        Log.i(TAG, formatMessage(module, "audit",
64	            "action=$action actor=$actorId entity=$entityType:$entityId"))
65	    }
66	
67	    fun request(method: String, path: String, statusCode: Int, durationMs: Long) {
68	        info("HTTP", "method=$method path=$path status=$statusCode duration=${durationMs}ms")
69	    }
70	
71	    private fun formatMessage(module: String, subModule: String?, message: String): String {
72	        return if (subModule != null) {
73	            "[$module][$subModule] $message"
74	        } else {
75	            "[$module] $message"
76	        }
77	    }
78	
79	    fun redact(message: String): String {
80	        if (!AppConfig.LOG_REDACTION_ENABLED) return message
81	        var result = message
82	        for (pattern in SENSITIVE_PATTERNS) {
83	            result = pattern.replace(result, REDACTION_REPLACEMENT)
84	        }
85	        return result
86	    }
87	
88	    private fun shouldLog(level: LogLevel): Boolean {
89	        val configLevel = try {
90	            LogLevel.valueOf(AppConfig.LOG_LEVEL.uppercase())
91	        } catch (_: Exception) {
92	            LogLevel.DEBUG
93	        }
94	        return level.ordinal >= configLevel.ordinal
95	    }
96	
97	    enum class LogLevel {
98	        DEBUG, INFO, WARN, ERROR
99	    }
100	}
